import React, { useEffect, useState } from 'react';
import { Pie, Bar, Line, Scatter } from 'react-chartjs-2';
import axios from 'axios';
import './Reports.css';
import './Reports.css';

import {
  Chart as ChartJS,
  ArcElement,
  BarElement,
  LineElement,
  PointElement,
  CategoryScale,
  LinearScale,
  Title,
  Tooltip,
  Legend,
} from 'chart.js';

ChartJS.register(
  ArcElement,
  BarElement,
  LineElement,
  PointElement,
  CategoryScale,
  LinearScale,
  Title,
  Tooltip,
  Legend
);

function Reports() {
  const [chartData, setChartData] = useState(null);

  useEffect(() => {
    axios.get('http://localhost:5000/api/ml/analytics')
      .then(response => {
        setChartData(response.data);
      })
      .catch(error => {
        console.error('Error fetching analytics data:', error);
      });
  }, []);

  if (!chartData) {
    return <div>Loading...</div>;
  }

  return (
    <div className="reports-container">
      <h1>Analytics Reports</h1>
      <div className="chart-section">
        <h2>Pie Chart</h2>
        <Pie data={chartData.pie} />
      </div>
      <div className="chart-section">
        <h2>Bar Chart</h2>
        <Bar data={chartData.bar} />
      </div>
      <div className="chart-section">
        <h2>Line Chart</h2>
        <Line data={chartData.line} />
      </div>
      <div className="chart-section">
        <h2>Scatter Chart</h2>
        <Scatter data={chartData.scatter} />
      </div>
    </div>
  );
}

export default Reports;
